const rows = $input.all().map(r => r.json);
const SCHEDULED = ['chief_of_staff'];
const RANK = { red: 2, yellow: 1, green: 0 };
const now = new Date();

const map = {};
for (const row of rows) {
  const key = row.id;
  if (!map[key]) {
    map[key] = { id: row.id, business_name: row.business_name, vertical: row.vertical, tier: row.tier, workflows: [] };
  }
  if (!row.workflow_name) continue;
  const isScheduled = SCHEDULED.some(n => row.workflow_name.toLowerCase().includes(n));
  const days = isScheduled ? 2 : 7;
  const threshold = new Date(now - days * 86400000);
  const lastTriggered = row.last_triggered_at ? new Date(row.last_triggered_at) : null;
  const failures = parseInt(row.failures_7d) || 0;
  let wfStatus = 'green';
  if (failures > 0) wfStatus = 'red';
  else if (!lastTriggered || lastTriggered < threshold) wfStatus = 'yellow';
  map[key].workflows.push({ workflow_name: row.workflow_name, status: wfStatus, last_failed_at: row.last_failed_at || null, failures_7d: failures, silence_days: days });
}

const clients = Object.values(map).map(c => {
  const worst = c.workflows.reduce((w, wf) => RANK[wf.status] > RANK[w] ? wf.status : w, 'green');
  return { ...c, status: worst };
});

const redClients = clients.filter(c => c.status === 'red');

if (redClients.length === 0) {
  return [{ json: { red_count: 0, slack_message: '' } }];
}

function fmt(iso) {
  return new Date(iso).toLocaleString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
}

const lines = [];
for (const c of redClients) {
  lines.push(':red_circle: *' + c.business_name + '*');
  for (const wf of c.workflows.filter(w => w.status === 'red')) {
    if (wf.failures_7d > 0) {
      const when = wf.last_failed_at ? fmt(wf.last_failed_at) : 'unknown time';
      lines.push('  \u2022 ' + wf.workflow_name + ' \u2014 ' + wf.failures_7d + ' failure' + (wf.failures_7d > 1 ? 's' : '') + ' in last 7 days (last: ' + when + ')');
    } else {
      lines.push('  \u2022 ' + wf.workflow_name + ' \u2014 no activity in ' + wf.silence_days + ' days');
    }
  }
}

const n = redClients.length;
const slack_message = '*Client Health Alert \u2014 ' + n + ' client' + (n > 1 ? 's' : '') + ' need' + (n === 1 ? 's' : '') + ' attention*\n\n' + lines.join('\n');

return [{ json: { red_count: n, slack_message } }];
